#include <stdio.h>
#include <string.h>
#include <errno.h>

/* == EXEMPLE ===============================================
 * Utiliser strerror pour afficher un message d'erreur custom
 * strerror(code) retourne un const char*
 * ========================================================= */
void example_strerror(void) {
    char msg[128];
    snprintf(msg, sizeof(msg), "Erreur custom: %s (code %d)", strerror(EEXIST), EEXIST);
    printf("%s\n", msg);
}
/* Resultat: Erreur custom: File exists (code 17) */

